<script lang="ts">
	import Cookies from 'js-cookie';
	import gridMode from '../store/gridMode';

	import { validation } from '../utils/validation.svelte';

	let searchString = '';

	const search = () => {
		if (validation.isURL([searchString])) {
			window.location.href = searchString;
		} else {
			window.location.href = 'https://www.google.com/search?q=' + encodeURIComponent(searchString);
		}
	};
</script>

<main id="navbarContainer">
	<main id="navbar">
		<a href="#/" class="nav-item title left">Shortcuts</a>
		<!-- svelte-ignore a11y-autofocus -->
		<input
			class="nav-item"
			id="searchBar"
			type="text"
			bind:value={searchString}
			on:keypress={(e) => {
				if (e.key === 'Enter') {
					search();
				}
			}}
			autoFocus />
		<button
			class="nav-item"
			on:click={() => {
				Object.keys(Cookies.get()).forEach(function (cookieName) {
					Cookies.remove(cookieName);
					gridMode.setIsNew(false);
				});
			}}>
			clear
		</button>
		<button
			class="nav-item"
			on:click={() => {
